module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;

    always @(A or B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend or divisor) begin
        if (dividend[15:8] >= divisor) begin
            quotient[15] = 1'b1;
            remainder = dividend[15:8] - divisor;
        end
        else begin
            quotient[15] = 1'b0;
            remainder = dividend[15:8];
